<template>
  <div class="page-wrap" v-loading="loading">
    <section class="dashboard-hero"><div><span>OPERATIONS OVERVIEW</span><h1>{{ greeting }}，{{ auth.admin?.name || '管理员' }}</h1><p>{{ fullDate }} · 平台运营数据已为您实时汇总</p></div><div class="hero-status"><i></i><div><span>系统状态</span><strong>运行正常</strong><small>最后更新 {{ currentTime }}</small></div></div></section>
    <section class="stats"><article v-for="item in cards" :key="item.key" :class="item.theme"><div class="icon"><el-icon><component :is="item.icon" /></el-icon></div><div><span>{{ item.label }}</span><strong>{{ item.value }}</strong><small>{{ item.note }}</small></div><div class="trend">{{ item.trend }}</div></article></section>
    <section class="dashboard-grid"><div class="panel resources"><div class="panel-head"><div><span>RESOURCE MATRIX</span><h2>医疗资源结构</h2></div><el-button class="soft-btn" @click="router.push('/departments')">查看科室</el-button></div><div class="resource-chart"><div v-for="item in resourceBars" :key="item.label" class="bar-row"><div><span>{{ item.label }}</span><strong>{{ item.value }}</strong></div><div class="track"><i :style="{ width: item.width + '%', background: item.color }"></i></div></div></div></div><div class="panel quick"><div class="panel-head"><div><span>QUICK ACCESS</span><h2>快捷管理入口</h2></div></div><div class="quick-grid"><button @click="router.push('/departments')"><span class="mint"><el-icon><OfficeBuilding /></el-icon></span><div><b>科室管理</b><small>维护诊疗科室信息</small></div><el-icon><ArrowRight /></el-icon></button><button @click="router.push('/doctors')"><span class="blue"><el-icon><UserFilled /></el-icon></span><div><b>医生管理</b><small>账号与专业资料</small></div><el-icon><ArrowRight /></el-icon></button><button @click="router.push('/medicines')"><span class="orange"><el-icon><FirstAidKit /></el-icon></span><div><b>药品管理</b><small>药品目录与库存</small></div><el-icon><ArrowRight /></el-icon></button><button @click="router.push('/ai-center')"><span class="purple"><el-icon><Monitor /></el-icon></span><div><b>AI运营中心</b><small>报告、质检与日志</small></div><el-icon><ArrowRight /></el-icon></button><button @click="router.push('/ai-knowledge')"><span class="mint"><el-icon><Notebook /></el-icon></span><div><b>AI知识库</b><small>维护智能问答资料</small></div><el-icon><ArrowRight /></el-icon></button><button @click="router.push('/profile')"><span class="purple"><el-icon><Setting /></el-icon></span><div><b>账户安全</b><small>修改管理员密码</small></div><el-icon><ArrowRight /></el-icon></button></div></div></section>
  </div>
</template>

<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'
import { useRouter } from 'vue-router'
import { getOverview } from '@/api/admin'
import { useAuthStore } from '@/stores/auth'
import type { OverviewStatistics } from '@/types'

const router = useRouter(); const auth = useAuthStore(); const loading = ref(false); const data = ref<OverviewStatistics>({ patientCount: 0, doctorCount: 0, departmentCount: 0, registrationCount: 0 })
const now = new Date(); const hour = now.getHours(); const greeting = hour < 11 ? '早上好' : hour < 14 ? '中午好' : hour < 18 ? '下午好' : '晚上好'; const fullDate = now.toLocaleDateString('zh-CN', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' }); const currentTime = now.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' })
const cards = computed(() => [
  { key:'patient', label:'患者总数', value:data.value.patientCount, note:'平台累计建档患者', trend:'PATIENT', icon:'User', theme:'teal' },
  { key:'doctor', label:'医生总数', value:data.value.doctorCount, note:'已纳入平台医生', trend:'DOCTOR', icon:'UserFilled', theme:'blue' },
  { key:'department', label:'科室总数', value:data.value.departmentCount, note:'当前开放诊疗科室', trend:'DEPT', icon:'OfficeBuilding', theme:'orange' },
  { key:'registration', label:'累计挂号', value:data.value.registrationCount, note:'平台累计预约记录', trend:'REG', icon:'Tickets', theme:'purple' }
])
const resourceBars = computed(() => { const max = Math.max(data.value.patientCount, data.value.doctorCount * 4, data.value.departmentCount * 12, 1); return [
  { label:'患者资源', value:data.value.patientCount, width:Math.max(12, data.value.patientCount/max*100), color:'#14a090' },
  { label:'医生资源', value:data.value.doctorCount, width:Math.max(12, data.value.doctorCount*4/max*100), color:'#577cc6' },
  { label:'科室资源', value:data.value.departmentCount, width:Math.max(12, data.value.departmentCount*12/max*100), color:'#dc8a28' }
]})
onMounted(async () => { loading.value = true; try { data.value = (await getOverview()).data.data } finally { loading.value = false } })
</script>

